import{i as e,r as t,s as n,t as r}from"./app-BvVgHaVZ.js";var i=JSON.parse(`{"path":"/tool-expansion-guide.html","title":"Tool Expansion Guide","lang":"en-US","frontmatter":{},"git":{"updatedTime":1778318743000,"contributors":[{"name":"JaguarM","username":"JaguarM","email":"39597011+JaguarM@users.noreply.github.com","commits":2,"url":"https://github.com/JaguarM"}],"changelog":[{"hash":"397520d0fe3de3dbcbf9c4d3713d731692ecb096","time":1778318743000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Add Unified Text Box docs and rename guides"},{"hash":"7efa96eb07dd2c49d47a3f27a89f3b5c4b7cc563","time":1778316600000,"email":"39597011+JaguarM@users.noreply.github.com","author":"JaguarM","message":"Add plugin registry and dynamic discovery"}]},"filePathRelative":"tool-expansion-guide.md"}`),a={name:`tool-expansion-guide.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="tool-expansion-guide" tabindex="-1"><a class="header-anchor" href="#tool-expansion-guide"><span>Tool Expansion Guide</span></a></h1><p>A reference for adding new plugins to EpsteinTool. Read the architecture section first — it explains the conventions every plugin relies on.</p><hr><h2 id="architecture-overview" tabindex="-1"><a class="header-anchor" href="#architecture-overview"><span>Architecture Overview</span></a></h2><h3 id="the-plugin-system" tabindex="-1"><a class="header-anchor" href="#the-plugin-system"><span>The Plugin System</span></a></h3><p>Plugins are standard Django apps that register themselves with the <strong>PDFTool registry</strong>. Each plugin defines a <code>tool.py</code> containing a class that inherits from <code>PDFTool</code> and is decorated with <code>@register_tool</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_tool/tool.py</span></span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>base <span class="token keyword">import</span> PDFTool</span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>registry <span class="token keyword">import</span> register_tool</span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@register_tool</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyTool</span><span class="token punctuation">(</span>PDFTool<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_tool&#39;</span></span>
<span class="line">    toolbar_button <span class="token operator">=</span> <span class="token string">&#39;my_tool/toolbar_button.html&#39;</span></span>
<span class="line">    <span class="token comment"># ... override only the fields you need</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The plugin&#39;s <code>apps.py</code> triggers registration with a single import:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_tool/apps.py</span></span>
<span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>apps <span class="token keyword">import</span> AppConfig</span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyToolConfig</span><span class="token punctuation">(</span>AppConfig<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_tool&#39;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">ready</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">import</span> my_tool<span class="token punctuation">.</span>tool  <span class="token comment"># noqa: F401 — registers MyTool</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>guesser_core/templates/guesser_core/index.html</code> iterates the registry to inject each tool&#39;s styles, toolbar buttons, options bars, sidebars, and scripts. <strong>No manual edits to <code>index.html</code> are needed.</strong></p><p>URL routes declared on the PDFTool class are auto-discovered by <code>epstein_project/urls.py</code>. <strong>No manual edits to <code>urls.py</code> are needed.</strong></p><p><code>settings.py</code> dynamically scans the project directory for folders containing <code>apps.py</code> and auto-appends them to <code>INSTALLED_APPS</code>. <strong>Dropping a plugin folder in enables it; deleting it disables it. No <code>settings.py</code> edits needed.</strong></p><h3 id="pdftool-base-class" tabindex="-1"><a class="header-anchor" href="#pdftool-base-class"><span>PDFTool Base Class</span></a></h3><p>All available fields with their defaults (<code>guesser_core/base.py</code>):</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">class</span> <span class="token class-name">PDFTool</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token boolean">None</span>                       <span class="token comment"># Required — e.g. &#39;my_tool&#39;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment"># URL routing</span></span>
<span class="line">    url_prefix <span class="token operator">=</span> <span class="token string">&#39;&#39;</span>                   <span class="token comment"># path prefix for include()</span></span>
<span class="line">    url_module <span class="token operator">=</span> <span class="token boolean">None</span>                 <span class="token comment"># dotted path to urls.py, or None</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment"># Template slots</span></span>
<span class="line">    styles <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span>                       <span class="token comment"># tuple/list of {&#39;path&#39;: &#39;...&#39;} dicts</span></span>
<span class="line">    toolbar_button <span class="token operator">=</span> <span class="token boolean">None</span>             <span class="token comment"># template path for toolbar button</span></span>
<span class="line">    options_bar <span class="token operator">=</span> <span class="token boolean">None</span>                <span class="token comment"># template path for options bar</span></span>
<span class="line">    sidebar <span class="token operator">=</span> <span class="token boolean">None</span>                    <span class="token comment"># template path for sidebar panel</span></span>
<span class="line">    shows_text_options_bar <span class="token operator">=</span> <span class="token boolean">False</span>    <span class="token comment"># include shared text_options_bar.html</span></span>
<span class="line">    has_sidebar_toggle <span class="token operator">=</span> <span class="token boolean">False</span>        <span class="token comment"># contributes a sidebar toggle button</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment"># Script injection</span></span>
<span class="line">    scripts_before_viewer <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span>        <span class="token comment"># scripts loaded before pdf-viewer.js</span></span>
<span class="line">    scripts_after_app <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span>            <span class="token comment"># scripts loaded after app.js</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Base class uses <strong>tuples</strong> for sequence defaults to avoid the mutable-default-on-a-class-attribute trap. Subclasses can safely assign lists.</p><h3 id="global-javascript-objects" tabindex="-1"><a class="header-anchor" href="#global-javascript-objects"><span>Global JavaScript Objects</span></a></h3><p>Two objects are defined in <code>guesser_core/static/guesser_core/state.js</code> and are available to all plugin scripts:</p><ul><li><strong><code>state</code></strong> — application state (current page, zoom, redactions, candidates, etc.)</li><li><strong><code>els</code></strong> — cached DOM element references (viewer, toolbars, sidebar buttons, etc.)</li></ul><h3 id="script-load-order" tabindex="-1"><a class="header-anchor" href="#script-load-order"><span>Script Load Order</span></a></h3><p>Scripts load in this order, controlled by the <code>scripts_before_viewer</code> and <code>scripts_after_app</code> fields on each PDFTool:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">state.js</span>
<span class="line">  → [tool.scripts_before_viewer for each registered tool]</span>
<span class="line">  → pdf-viewer.js</span>
<span class="line">  → ui-events.js</span>
<span class="line">  → app.js                ← defines window.openSubtoolbar, window.openRightPanel</span>
<span class="line">  → mobile.js</span>
<span class="line">  → [tool.scripts_after_app for each registered tool]</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Scripts in <code>scripts_before_viewer</code> run before <code>app.js</code>, so they cannot call <code>app.js</code> functions at module scope — only inside event handlers. Scripts in <code>scripts_after_app</code> can safely reference <code>app.js</code> globals.</p><h3 id="two-ui-patterns" tabindex="-1"><a class="header-anchor" href="#two-ui-patterns"><span>Two UI Patterns</span></a></h3><p>There are two distinct plugin UI patterns. Choose one based on what your tool needs:</p><table><thead><tr><th>Pattern</th><th>Used by</th><th>Adds</th></tr></thead><tbody><tr><td><strong>Subtoolbar</strong></td><td><code>webgl_mask</code>, <code>embedded_text_viewer</code></td><td>A toolbar button that swaps the options bar row</td></tr><tr><td><strong>Right Panel</strong></td><td><code>redaction_matching</code></td><td>A toolbar button that opens a full-height side panel</td></tr></tbody></table><hr><h2 id="pattern-a-—-subtoolbar-plugin" tabindex="-1"><a class="header-anchor" href="#pattern-a-—-subtoolbar-plugin"><span>Pattern A — Subtoolbar Plugin</span></a></h2><p>Use this when your tool needs a row of controls (sliders, selects, checkboxes) rather than a persistent panel. Examples: <code>webgl_mask</code>, <code>embedded_text_viewer</code> formatting bar.</p><p>The subtoolbar row is mutually exclusive — only one bar is visible at a time. This is enforced by <code>window.openSubtoolbar</code>, defined in <code>app.js</code>.</p><h3 id="file-structure" tabindex="-1"><a class="header-anchor" href="#file-structure"><span>File Structure</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">my_tool/</span>
<span class="line">  apps.py                  ← AppConfig with ready() importing tool.py</span>
<span class="line">  tool.py                  ← PDFTool subclass with @register_tool</span>
<span class="line">  templates/my_tool/</span>
<span class="line">    toolbar_button.html    ← button injected into #toolbar-right</span>
<span class="line">    options_bar.html       ← bar injected into #text-toolbar-row</span>
<span class="line">  static/my_tool/</span>
<span class="line">    my-tool.js             ← toggle logic + tool behaviour</span>
<span class="line">  views.py, urls.py, ...</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-1-—-define-your-tool" tabindex="-1"><a class="header-anchor" href="#step-1-—-define-your-tool"><span>Step 1 — Define Your Tool</span></a></h3><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_tool/tool.py</span></span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>base <span class="token keyword">import</span> PDFTool</span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>registry <span class="token keyword">import</span> register_tool</span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@register_tool</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyTool</span><span class="token punctuation">(</span>PDFTool<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_tool&#39;</span></span>
<span class="line">    url_module <span class="token operator">=</span> <span class="token string">&#39;my_tool.urls&#39;</span>        <span class="token comment"># omit if no backend routes</span></span>
<span class="line">    toolbar_button <span class="token operator">=</span> <span class="token string">&#39;my_tool/toolbar_button.html&#39;</span></span>
<span class="line">    options_bar <span class="token operator">=</span> <span class="token string">&#39;my_tool/options_bar.html&#39;</span></span>
<span class="line">    scripts_after_app <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token punctuation">{</span><span class="token string">&#39;path&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;my_tool/my-tool.js&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;version&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;v=1&#39;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-2-—-appconfig" tabindex="-1"><a class="header-anchor" href="#step-2-—-appconfig"><span>Step 2 — AppConfig</span></a></h3><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_tool/apps.py</span></span>
<span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>apps <span class="token keyword">import</span> AppConfig</span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyToolConfig</span><span class="token punctuation">(</span>AppConfig<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_tool&#39;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">ready</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">import</span> my_tool<span class="token punctuation">.</span>tool  <span class="token comment"># noqa: F401</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-3-—-toolbar-button" tabindex="-1"><a class="header-anchor" href="#step-3-—-toolbar-button"><span>Step 3 — Toolbar Button</span></a></h3><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token comment">&lt;!-- templates/my_tool/toolbar_button.html --&gt;</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>toggle-my-tool<span class="token punctuation">&quot;</span></span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>icon-button<span class="token punctuation">&quot;</span></span> <span class="token attr-name">title</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>My Tool<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>material-symbols-outlined<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>your_icon_name<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-4-—-options-bar" tabindex="-1"><a class="header-anchor" href="#step-4-—-options-bar"><span>Step 4 — Options Bar</span></a></h3><p>Start with <code>class=&quot;options-bar hidden&quot;</code>. The bar must be hidden by default; <code>openSubtoolbar</code> manages visibility from here.</p><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token comment">&lt;!-- templates/my_tool/options_bar.html --&gt;</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>my-tool-bar<span class="token punctuation">&quot;</span></span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>options-bar hidden<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>options-divider<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>options-group<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>options-group-header<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>My Setting<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>options-group-controls<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>range<span class="token punctuation">&quot;</span></span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>my-slider<span class="token punctuation">&quot;</span></span> <span class="token attr-name">min</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>0<span class="token punctuation">&quot;</span></span> <span class="token attr-name">max</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>100<span class="token punctuation">&quot;</span></span> <span class="token attr-name">value</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>50<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-5-—-javascript-toggle" tabindex="-1"><a class="header-anchor" href="#step-5-—-javascript-toggle"><span>Step 5 — JavaScript Toggle</span></a></h3><p>Call <code>openSubtoolbar</code> inside the click handler. Because <code>app.js</code> loads before <code>scripts_after_app</code>, you can safely reference <code>openSubtoolbar</code> directly. If your script is in <code>scripts_before_viewer</code> instead, guard the call with <code>typeof openSubtoolbar === &#39;function&#39;</code>.</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// static/my_tool/my-tool.js</span></span>
<span class="line"></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-tool&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> bar <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-tool-bar&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">const</span> btn <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-tool&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">if</span> <span class="token punctuation">(</span>bar<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Open: hand off to the global coordinator</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> openSubtoolbar <span class="token operator">===</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token function">openSubtoolbar</span><span class="token punctuation">(</span>bar<span class="token punctuation">,</span> btn<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">else</span> <span class="token punctuation">{</span> bar<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> btn<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// Close: revert to the default text-options-bar</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> openSubtoolbar <span class="token operator">===</span> <span class="token string">&#39;function&#39;</span><span class="token punctuation">)</span> <span class="token function">openSubtoolbar</span><span class="token punctuation">(</span><span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">else</span> <span class="token punctuation">{</span> bar<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> btn<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-6-—-register-opensubtoolbar-awareness-in-app-js" tabindex="-1"><a class="header-anchor" href="#step-6-—-register-opensubtoolbar-awareness-in-app-js"><span>Step 6 — Register <code>openSubtoolbar</code> Awareness in <code>app.js</code></span></a></h3><p><code>window.openSubtoolbar</code> in <code>app.js</code> hides all known bars when switching. Add your new bar to its hide list so it closes when another tool opens:</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// guesser_core/static/guesser_core/app.js — inside openSubtoolbar()</span></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-tool-bar&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-tool&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That&#39;s it. No changes to <code>index.html</code>, <code>urls.py</code>, or <code>settings.py</code> — the registry and dynamic discovery handle everything.</p><hr><h2 id="pattern-b-—-right-panel-plugin" tabindex="-1"><a class="header-anchor" href="#pattern-b-—-right-panel-plugin"><span>Pattern B — Right Panel Plugin</span></a></h2><p>Use this when your tool needs a persistent, scrollable side panel. The right panel area is mutually exclusive with the AI Unredactor Tools sidebar — opening one closes the other.</p><h3 id="file-structure-1" tabindex="-1"><a class="header-anchor" href="#file-structure-1"><span>File Structure</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">my_panel/</span>
<span class="line">  apps.py                  ← AppConfig with ready() importing tool.py</span>
<span class="line">  tool.py                  ← PDFTool subclass with @register_tool</span>
<span class="line">  templates/my_panel/</span>
<span class="line">    toolbar_button.html    ← button injected into #toolbar-right</span>
<span class="line">    panel.html             ← &lt;aside&gt; injected as sidebar</span>
<span class="line">  static/my_panel/</span>
<span class="line">    my-panel.js            ← open/close logic + panel behaviour</span>
<span class="line">  views.py, urls.py, ...</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-1-—-define-your-tool-1" tabindex="-1"><a class="header-anchor" href="#step-1-—-define-your-tool-1"><span>Step 1 — Define Your Tool</span></a></h3><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_panel/tool.py</span></span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>base <span class="token keyword">import</span> PDFTool</span>
<span class="line"><span class="token keyword">from</span> guesser_core<span class="token punctuation">.</span>registry <span class="token keyword">import</span> register_tool</span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@register_tool</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyPanel</span><span class="token punctuation">(</span>PDFTool<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_panel&#39;</span></span>
<span class="line">    toolbar_button <span class="token operator">=</span> <span class="token string">&#39;my_panel/toolbar_button.html&#39;</span></span>
<span class="line">    sidebar <span class="token operator">=</span> <span class="token string">&#39;my_panel/panel.html&#39;</span></span>
<span class="line">    has_sidebar_toggle <span class="token operator">=</span> <span class="token boolean">True</span>    <span class="token comment"># if this tool should control sidebar visibility</span></span>
<span class="line">    scripts_after_app <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token punctuation">{</span><span class="token string">&#39;path&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;my_panel/my-panel.js&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;version&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;v=1&#39;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-2-—-appconfig-1" tabindex="-1"><a class="header-anchor" href="#step-2-—-appconfig-1"><span>Step 2 — AppConfig</span></a></h3><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token comment"># my_panel/apps.py</span></span>
<span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>apps <span class="token keyword">import</span> AppConfig</span>
<span class="line"></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyPanelConfig</span><span class="token punctuation">(</span>AppConfig<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_panel&#39;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">def</span> <span class="token function">ready</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">import</span> my_panel<span class="token punctuation">.</span>tool  <span class="token comment"># noqa: F401</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-3-—-toolbar-button-1" tabindex="-1"><a class="header-anchor" href="#step-3-—-toolbar-button-1"><span>Step 3 — Toolbar Button</span></a></h3><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token comment">&lt;!-- templates/my_panel/toolbar_button.html --&gt;</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>toggle-my-panel<span class="token punctuation">&quot;</span></span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>icon-button<span class="token punctuation">&quot;</span></span> <span class="token attr-name">title</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>My Panel<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>material-symbols-outlined<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>your_icon_name<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-4-—-panel-html" tabindex="-1"><a class="header-anchor" href="#step-4-—-panel-html"><span>Step 4 — Panel HTML</span></a></h3><p>The panel is included inside <code>#tools-sidebar</code> via the <code>sidebar</code> field. The template auto-includes it when iterating registered tools.</p><div class="language-html line-numbers-mode" data-highlighter="prismjs" data-ext="html"><pre><code class="language-html"><span class="line"><span class="token comment">&lt;!-- templates/my_panel/panel.html --&gt;</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>my-panel<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>my-panel-header<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span><span class="token punctuation">&gt;</span></span>My Panel<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token comment">&lt;!-- panel content --&gt;</span></span>
<span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-5-—-javascript-toggle-1" tabindex="-1"><a class="header-anchor" href="#step-5-—-javascript-toggle-1"><span>Step 5 — JavaScript Toggle</span></a></h3><p>Right panels manage their own open/close. When <strong>opening</strong>, close other sidebars to enforce mutual exclusivity:</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// static/my_panel/my-panel.js</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">openMyPanel</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// Mutual exclusivity: close the tools sidebar if open</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;tools-sidebar&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-tools&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-panel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-panel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">closeMyPanel</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-panel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-panel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-panel&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-panel&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token operator">?</span> <span class="token function">openMyPanel</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token operator">:</span> <span class="token function">closeMyPanel</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="step-6-—-make-tools-sidebar-aware-of-your-panel" tabindex="-1"><a class="header-anchor" href="#step-6-—-make-tools-sidebar-aware-of-your-panel"><span>Step 6 — Make <code>#tools-sidebar</code> Aware of Your Panel</span></a></h3><p>When <code>#tools-sidebar</code> opens, it should close your panel. Add your panel to the <code>openRightPanel</code> function in <code>app.js</code>:</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// guesser_core/static/guesser_core/app.js — inside openRightPanel()</span></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;my-panel&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&#39;toggle-my-panel&#39;</span><span class="token punctuation">)</span><span class="token operator">?.</span>classList<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string">&#39;active&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That&#39;s it. No changes to <code>index.html</code>, <code>urls.py</code>, or <code>settings.py</code>.</p><hr><h2 id="adding-a-backend-api-endpoint" tabindex="-1"><a class="header-anchor" href="#adding-a-backend-api-endpoint"><span>Adding a Backend API Endpoint</span></a></h2><p>If your plugin needs to process data server-side, define your URL routing on the PDFTool class:</p><p><strong><code>tool.py</code></strong> — set <code>url_prefix</code> and <code>url_module</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token decorator annotation punctuation">@register_tool</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">MyTool</span><span class="token punctuation">(</span>PDFTool<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&#39;my_tool&#39;</span></span>
<span class="line">    url_prefix <span class="token operator">=</span> <span class="token string">&#39;my-tool/&#39;</span>           <span class="token comment"># routes will be prefixed: /my-tool/...</span></span>
<span class="line">    url_module <span class="token operator">=</span> <span class="token string">&#39;my_tool.urls&#39;</span>       <span class="token comment"># points to your urls.py</span></span>
<span class="line">    <span class="token comment"># ... other fields</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>views.py</code></strong> — write your view, returning <code>JsonResponse</code>:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>http <span class="token keyword">import</span> JsonResponse</span>
<span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>views<span class="token punctuation">.</span>decorators<span class="token punctuation">.</span>csrf <span class="token keyword">import</span> csrf_exempt</span>
<span class="line"></span>
<span class="line"><span class="token decorator annotation punctuation">@csrf_exempt</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">my_endpoint</span><span class="token punctuation">(</span>request<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> request<span class="token punctuation">.</span>method <span class="token operator">!=</span> <span class="token string">&#39;POST&#39;</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> JsonResponse<span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token string">&#39;detail&#39;</span><span class="token punctuation">:</span> <span class="token string">&#39;Method not allowed&#39;</span><span class="token punctuation">}</span><span class="token punctuation">,</span> status<span class="token operator">=</span><span class="token number">405</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment"># ... your logic ...</span></span>
<span class="line">    <span class="token keyword">return</span> JsonResponse<span class="token punctuation">(</span><span class="token punctuation">{</span><span class="token string">&#39;result&#39;</span><span class="token punctuation">:</span> <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong><code>urls.py</code></strong> — register the route:</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> django<span class="token punctuation">.</span>urls <span class="token keyword">import</span> path</span>
<span class="line"><span class="token keyword">from</span> <span class="token punctuation">.</span> <span class="token keyword">import</span> views</span>
<span class="line"></span>
<span class="line">urlpatterns <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">    path<span class="token punctuation">(</span><span class="token string">&#39;my-endpoint&#39;</span><span class="token punctuation">,</span> views<span class="token punctuation">.</span>my_endpoint<span class="token punctuation">,</span> name<span class="token operator">=</span><span class="token string">&#39;my_endpoint&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The route is auto-discovered from <code>tool.url_module</code> — no need to edit <code>epstein_project/urls.py</code>.</p><blockquote><p><strong>Note for backend-only apps</strong> (no UI, no PDFTool): Apps like <code>extracted_text</code> that only provide API endpoints can still use the legacy <code>AppConfig</code> approach with <code>url_prefix</code> and <code>url_module</code> as class attributes on the AppConfig. The URL auto-discovery falls back to AppConfig for apps without a registered PDFTool.</p></blockquote><hr><h2 id="existing-plugins-—-quick-reference" tabindex="-1"><a class="header-anchor" href="#existing-plugins-—-quick-reference"><span>Existing Plugins — Quick Reference</span></a></h2><table><thead><tr><th>App</th><th>Type</th><th>PDFTool class</th><th>Toggle Button ID</th><th>Bar / Panel ID</th></tr></thead><tbody><tr><td><code>text_tool</code></td><td>Subtoolbar</td><td><code>TextTool</code></td><td><code>toggle-text-tool</code></td><td><code>text-tool-bar</code></td></tr><tr><td><code>webgl_mask</code></td><td>Subtoolbar</td><td><code>WebglMaskTool</code></td><td><code>toggle-webgl</code></td><td><code>webgl-options-bar</code></td></tr><tr><td><code>embedded_text_viewer</code></td><td>Subtoolbar</td><td><code>EmbeddedTextViewerTool</code></td><td><code>toggle-embedded-viewer</code></td><td><code>etv-bar</code></td></tr><tr><td><code>tesseract_ocr</code></td><td>Toolbar button</td><td><code>TesseractOcrTool</code></td><td><code>toggle-ocr</code></td><td>—</td></tr><tr><td><code>redaction_matching</code></td><td>Right Panel</td><td><code>RedactionMatchingTool</code></td><td><code>toggle-tools</code></td><td><code>tools-sidebar</code></td></tr><tr><td><code>extracted_text</code></td><td>Backend-only</td><td><em>(none)</em></td><td>—</td><td>—</td></tr><tr><td><code>guesser_core</code></td><td>Core (always on)</td><td><em>(none)</em></td><td>—</td><td><code>text-options-bar</code></td></tr></tbody></table><hr><h2 id="checklist-—-adding-a-new-tool" tabindex="-1"><a class="header-anchor" href="#checklist-—-adding-a-new-tool"><span>Checklist — Adding a New Tool</span></a></h2><ol><li><strong>Create the Django app directory</strong> (<code>my_tool/</code>)</li><li><strong>Write <code>my_tool/tool.py</code></strong> — subclass <code>PDFTool</code>, decorate with <code>@register_tool</code>, override only what you need</li><li><strong>Write <code>my_tool/apps.py</code></strong> — <code>ready()</code> does <code>import my_tool.tool</code></li><li><strong>Create templates</strong> — <code>toolbar_button.html</code>, <code>options_bar.html</code>, and/or <code>sidebar.html</code></li><li><strong>Create static assets</strong> — JS and CSS files referenced in your tool class</li><li><em>(Optional)</em> If using subtoolbar: add your bar to <code>openSubtoolbar()</code> hide list in <code>app.js</code></li><li><em>(Optional)</em> If using right panel: add your panel to <code>openRightPanel()</code> hide list in <code>app.js</code></li></ol><p><strong>Zero changes needed to</strong>: <code>index.html</code>, <code>epstein_project/urls.py</code>, <code>settings.py</code>, or any other plugin&#39;s code.</p><p><strong>To disable a plugin</strong>: delete its folder. Django&#39;s dynamic discovery in <code>settings.py</code> won&#39;t find it and the app simply won&#39;t load.</p><hr><h2 id="best-practices" tabindex="-1"><a class="header-anchor" href="#best-practices"><span>Best Practices</span></a></h2><ul><li><strong>Never use <code>display: block</code> directly.</strong> Always toggle the <code>.hidden</code> class. Sidebars use CSS transitions keyed on <code>.hidden</code>; bypassing it breaks animations.</li><li><strong>Use optional chaining (<code>?.</code>) on all <code>getElementById</code> calls</strong> in plugin JS. This ensures your script doesn&#39;t throw if the plugin is removed.</li><li><strong>Guard <code>openSubtoolbar</code> calls</strong> with <code>typeof openSubtoolbar === &#39;function&#39;</code> when your script is in <code>scripts_before_viewer</code>. Scripts in <code>scripts_after_app</code> can reference it directly.</li><li><strong>Keep plugin logic self-contained.</strong> Views, URLs, and business logic belong in the plugin app. The only cross-plugin touchpoints are <code>openSubtoolbar</code> (subtoolbar pattern) and the two lines in <code>openRightPanel</code> (right-panel pattern).</li><li><strong>Disable by deleting the folder.</strong> <code>settings.py</code> dynamically scans for plugin directories — removing the folder is the off-switch. No manual <code>INSTALLED_APPS</code> edits needed.</li><li><strong>Use tuples or lists for tool config fields.</strong> The base class uses tuples for immutable defaults, but subclasses can safely assign lists. Both work in Django template iteration.</li></ul>`,91)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};